1	import { useCallback, useSyncExternalStore } from "react";
2	import { Option, Schema } from "effect";
3	import { type ProviderKind, type ProviderServiceTier } from "@t3tools/contracts";
4	import { getDefaultModel, getModelOptions, normalizeModelSlug } from "@t3tools/shared/model";
