### Step 3 — Rewrite `apps/web/src/hooks/useTheme.ts`

This is the most surgical change. The goal is to:
1. Extend the stored `AppTheme` type from `"light" | "dark" | "system"` to `BuiltInThemeId | "system"`.
2. Apply a `data-theme` attribute alongside the `.dark` class toggle.
3. Preserve the `resolvedTheme: "light" | "dark"` return value consumed by `DiffWorkerPoolProvider`, `DiffPanel`, `ChatView`, `ChatMarkdown`, and `ComposerPromptEditor`.
4. Add `resolvedThemeId: BuiltInThemeId` as a new output.
5. Migrate legacy stored values `"dark"` and `"light"` to `"t3-dark"` and `"t3-light"` on read.

**Complete design for the rewritten module:**

```typescript
import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type BuiltInThemeId,
  BUILT_IN_THEME_IDS,
  getThemeById,
  resolveSystemThemeId,
} from "@t3tools/shared/theme";

export type AppTheme = BuiltInThemeId | "system";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// Module-level state — mirrors existing pattern exactly
let listeners: Array<() => void> = [];
let lastSnapshot: { theme: AppTheme; systemDark: boolean } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateLegacyTheme(raw: string | null): AppTheme {
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return "system";
  if ((BUILT_IN_THEME_IDS as ReadonlyArray<string>).includes(raw ?? "")) {
    return raw as BuiltInThemeId;
  }
  return "system";
}

function getStored(): AppTheme {
  const raw = localStorage.getItem(STORAGE_KEY);
  return migrateLegacyTheme(raw);
}

export function applyTheme(themeId: BuiltInThemeId, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const def = getThemeById(themeId);
  document.documentElement.dataset["theme"] = themeId;
  document.documentElement.classList.toggle("dark", def.isDark);
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function resolveThemeId(theme: AppTheme): BuiltInThemeId {
  return theme === "system" ? resolveSystemThemeId(getSystemDark()) : theme;
}

// Apply immediately on module load to prevent flash
applyTheme(resolveThemeId(getStored()));

function getSnapshot(): { theme: AppTheme; systemDark: boolean } {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;
  if (
    lastSnapshot &&
    lastSnapshot.theme === theme &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }
  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme(resolveSystemThemeId(mq.matches), true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveThemeId(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { theme, systemDark } = snapshot;

  const resolvedThemeId: BuiltInThemeId =
    theme === "system" ? resolveSystemThemeId(systemDark) : theme;

  const resolvedTheme: "light" | "dark" = getThemeById(resolvedThemeId).isDark
    ? "dark"
    : "light";

  const setTheme = useCallback((next: AppTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(resolveThemeId(next), true);
    emitChange();
  }, []);

  useEffect(() => {
    applyTheme(resolvedThemeId);
  }, [resolvedThemeId]);

  return { theme, setTheme, resolvedTheme, resolvedThemeId } as const;
}
```

Key design decisions:
- `applyTheme` is now exported so `ThemeProvider` can call it directly without going through the hook.
- The `useEffect` now depends on `resolvedThemeId` rather than the raw stored `theme`. This correctly handles the case where the stored preference is `"system"` and the OS changes — the effect still fires because `resolvedThemeId` changed even though `theme` didn't.
- `resolvedTheme: "light" | "dark"` is preserved with identical semantics so all six existing call sites (`DiffWorkerPoolProvider`, `DiffPanel`, `ChatView` ×3, `ChatMarkdown`) need zero changes.
- The `migrateLegacyTheme` function runs on every `getStored()` call. It intentionally does NOT write back the migrated value to localStorage — migration only happens when the user actively opens settings and sets a new theme. This avoids surprise writes.

