# Custom Theme System — T3 Code

## Context

T3 Code's current theme system only supports `"light" | "dark" | "system"` and applies a single `.dark` CSS class to `<html>`. The goal is to introduce named built-in themes (`"t3-dark"`, `"t3-light"`, `"t3-midnight"`) with per-area color tokens (background, foreground, accent, sidebar, editor, terminal, status bar), a theme selector with preview swatches, and CSS custom properties applied via a `data-theme` attribute — all while preserving the `resolvedTheme: "light" | "dark"` return value that `DiffWorkerPoolProvider` and other consumers depend on.

---

## Implementation Order

### 1. NEW: `packages/shared/src/theme.ts`

Pure TypeScript, zero dependencies. Source of truth for theme identity, metadata, and color tokens.

```ts
export const BUILT_IN_THEME_IDS = ["t3-dark", "t3-light", "t3-midnight"] as const;
export type BuiltInThemeId = (typeof BUILT_IN_THEME_IDS)[number];

export interface ThemeColorTokens {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface ThemeDefinition {
  id: BuiltInThemeId;
  name: string;
  isDark: boolean;
  colors: ThemeColorTokens;
}

export const BUILT_IN_THEMES: ReadonlyArray<ThemeDefinition> = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0e1218",
      foreground: "#edf1f7",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#131820",
      editor: "#111519",
      terminal: "#0a0e13",
      statusBar: "#1a2030",
    },
  },
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#1c2129",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f6f8",
      editor: "#fafbfc",
      terminal: "#f0f1f3",
      statusBar: "#e8eaed",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#070b10",
      foreground: "#c8d4e8",
      accent: "oklch(0.65 0.18 230)",
      sidebar: "#0b1018",
      editor: "#060a0f",
      terminal: "#040709",
      statusBar: "#0d1520",
    },
  },
];

export function getThemeById(id: BuiltInThemeId): ThemeDefinition {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown theme: ${id}`);
  return theme;
}

export function resolveSystemThemeId(systemDark: boolean): BuiltInThemeId {
  return systemDark ? "t3-dark" : "t3-light";
}
```

---

### 2. MODIFY: `packages/shared/package.json`

Add one entry to the `exports` map, matching the existing pattern exactly:

```json
"./theme": {
  "types": "./src/theme.ts",
  "import": "./src/theme.ts"
}
```

---

### 3. REWRITE: `apps/web/src/hooks/useTheme.ts`

Key changes vs. current file:
- `AppTheme = BuiltInThemeId | "system"` replaces `"light" | "dark" | "system"`
- `migrateLegacyTheme()` converts stored `"dark"` → `"t3-dark"`, `"light"` → `"t3-light"` on read (does not write back)
- `applyTheme(themeId: BuiltInThemeId)` now sets `document.documentElement.dataset.theme = themeId` AND toggles `.dark` based on `getThemeById(themeId).isDark`
- `resolveThemeId(pref: AppTheme): BuiltInThemeId` maps `"system"` using `resolveSystemThemeId(getSystemDark())`
- Module-load call becomes `applyTheme(resolveThemeId(getStored()))` (same flash-prevention pattern)
- `useTheme()` returns `{ theme, setTheme, resolvedTheme, resolvedThemeId }` — **`resolvedTheme: "light" | "dark"` is preserved** for all existing callers
- `useEffect` depends on `resolvedThemeId` (not raw `theme`) so OS changes on `"system"` still fire the effect
- `applyTheme` is exported so `ThemeProvider` can call it without going through the hook

```ts
import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type BuiltInThemeId,
  BUILT_IN_THEME_IDS,
  getThemeById,
  resolveSystemThemeId,
} from "@t3tools/shared/theme";

export type AppTheme = BuiltInThemeId | "system";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: { theme: AppTheme; systemDark: boolean } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateLegacyTheme(raw: string | null): AppTheme {
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return "system";
  if ((BUILT_IN_THEME_IDS as ReadonlyArray<string>).includes(raw ?? "")) {
    return raw as BuiltInThemeId;
  }
  return "system";
}

function getStored(): AppTheme {
  return migrateLegacyTheme(localStorage.getItem(STORAGE_KEY));
}

export function resolveThemeId(pref: AppTheme): BuiltInThemeId {
  return pref === "system" ? resolveSystemThemeId(getSystemDark()) : pref;
}

export function applyTheme(themeId: BuiltInThemeId, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const def = getThemeById(themeId);
  document.documentElement.dataset["theme"] = themeId;
  document.documentElement.classList.toggle("dark", def.isDark);
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(resolveThemeId(getStored()));

function getSnapshot(): { theme: AppTheme; systemDark: boolean } {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;
  if (lastSnapshot?.theme === theme && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }
  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme(resolveSystemThemeId(mq.matches), true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveThemeId(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { theme, systemDark } = snapshot;
  const resolvedThemeId: BuiltInThemeId =
    theme === "system" ? resolveSystemThemeId(systemDark) : theme;
  const resolvedTheme: "light" | "dark" = getThemeById(resolvedThemeId).isDark ? "dark" : "light";
  const setTheme = useCallback((next: AppTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(resolveThemeId(next), true);
    emitChange();
  }, []);
  useEffect(() => {
    applyTheme(resolvedThemeId);
  }, [resolvedThemeId]);
  return { theme, setTheme, resolvedTheme, resolvedThemeId } as const;
}
```

---

### 4. NEW: `apps/web/src/components/ThemeProvider.tsx`

Ensures the `subscribe` listener (media query + storage events) is always active for the lifetime of the app, even when no route-level component calls `useTheme()`.

```tsx
import { useTheme } from "~/hooks/useTheme";

export function ThemeProvider() {
  useTheme(); // keeps DOM data-theme + .dark class in sync; returns null
  return null;
}
```

---

### 5. MODIFY: `apps/web/src/router.ts`

Add `ThemeProvider` as a sibling inside `StoreProvider`:

```ts
import { createElement } from "react";
import { ThemeProvider } from "./components/ThemeProvider";
// ... existing imports

Wrap: ({ children }) =>
  createElement(
    QueryClientProvider,
    { client: queryClient },
    createElement(
      StoreProvider,
      null,
      createElement(ThemeProvider, null),
      children,
    ),
  ),
```

If `StoreProvider`'s `children` prop is typed narrowly and rejects multiple children, wrap in a Fragment instead.

---

### 6. MODIFY: `apps/web/src/index.css`

Append at the end of the file. Uses `--t3-*` namespace to avoid collisions with existing Tailwind tokens (`--background`, `--foreground`, etc.). The `.dark` class and existing Tailwind variables remain unchanged.

```css
/* Named theme token blocks */

:root[data-theme="t3-dark"] {
  --t3-background: #0e1218;
  --t3-foreground: #edf1f7;
  --t3-accent: oklch(0.588 0.217 264);
  --t3-sidebar: #131820;
  --t3-editor: #111519;
  --t3-terminal: #0a0e13;
  --t3-status-bar: #1a2030;
}

:root[data-theme="t3-light"] {
  --t3-background: #ffffff;
  --t3-foreground: #1c2129;
  --t3-accent: oklch(0.488 0.217 264);
  --t3-sidebar: #f5f6f8;
  --t3-editor: #fafbfc;
  --t3-terminal: #f0f1f3;
  --t3-status-bar: #e8eaed;
}

:root[data-theme="t3-midnight"] {
  --t3-background: #070b10;
  --t3-foreground: #c8d4e8;
  --t3-accent: oklch(0.65 0.18 230);
  --t3-sidebar: #0b1018;
  --t3-editor: #060a0f;
  --t3-terminal: #040709;
  --t3-status-bar: #0d1520;
}
```

---

### 7. NEW: `apps/web/src/components/ThemeSelector.tsx`

Replaces the inline radiogroup in the settings page. Accepts controlled props so the parent can own state (easier to test in isolation).

```tsx
import { BUILT_IN_THEMES, type BuiltInThemeId, type ThemeDefinition } from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";
import type { AppTheme } from "~/hooks/useTheme";

interface ThemeSelectorProps {
  value: AppTheme;
  resolvedThemeId: BuiltInThemeId;
  onChange: (next: AppTheme) => void;
}

export function ThemeSelector({ value, resolvedThemeId, onChange }: ThemeSelectorProps) {
  return (
    <div role="radiogroup" aria-label="Theme preference" className="space-y-2">
      {/* System option */}
      <button
        type="button"
        role="radio"
        aria-checked={value === "system"}
        onClick={() => onChange("system")}
        className={cn(
          "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
          value === "system"
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent",
        )}
      >
        <span className="flex flex-col">
          <span className="text-sm font-medium">System</span>
          <span className="text-xs">Match your OS appearance setting.</span>
        </span>
        {value === "system" && (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Selected
          </span>
        )}
      </button>

      {/* Named themes */}
      {BUILT_IN_THEMES.map((def) => (
        <ThemeOption
          key={def.id}
          def={def}
          selected={value === def.id}
          onChange={onChange}
        />
      ))}
    </div>
  );
}

function ThemeOption({
  def,
  selected,
  onChange,
}: {
  def: ThemeDefinition;
  selected: boolean;
  onChange: (next: AppTheme) => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={() => onChange(def.id)}
      className={cn(
        "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
    >
      <span className="flex flex-col gap-1.5">
        <span className="text-sm font-medium">{def.name}</span>
        {/* Color swatches: background, accent, sidebar */}
        <span className="flex items-center gap-1" aria-hidden="true">
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.background }}
          />
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.accent }}
          />
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.sidebar }}
          />
        </span>
      </span>
      {selected && (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      )}
    </button>
  );
}
```

Note: swatches read from `def.colors` (JS values), not CSS variables — they render correctly before the browser resolves `data-theme` CSS.

---

### 8. MODIFY: `apps/web/src/routes/_chat.settings.tsx`

- Remove the `THEME_OPTIONS` const (currently lines 25–41)
- Remove the inline `<div role="radiogroup">` block and its "Active theme" paragraph from the Appearance section
