const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: { theme: AppTheme; systemDark: boolean } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateLegacyTheme(raw: string | null): AppTheme {
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return "system";
  if ((BUILT_IN_THEME_IDS as ReadonlyArray<string>).includes(raw ?? "")) {
    return raw as BuiltInThemeId;
  }
  return "system";
}

function getStored(): AppTheme {
  return migrateLegacyTheme(localStorage.getItem(STORAGE_KEY));
}

export function resolveThemeId(pref: AppTheme): BuiltInThemeId {
  return pref === "system" ? resolveSystemThemeId(getSystemDark()) : pref;
}

export function applyTheme(themeId: BuiltInThemeId, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const def = getThemeById(themeId);
  document.documentElement.dataset["theme"] = themeId;
  document.documentElement.classList.toggle("dark", def.isDark);
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(resolveThemeId(getStored()));

function getSnapshot(): { theme: AppTheme; systemDark: boolean } {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;
  if (lastSnapshot?.theme === theme && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }
  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme(resolveSystemThemeId(mq.matches), true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveThemeId(getStored()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { theme, systemDark } = snapshot;
  const resolvedThemeId: BuiltInThemeId =
    theme === "system" ? resolveSystemThemeId(systemDark) : theme;
  const resolvedTheme: "light" | "dark" = getThemeById(resolvedThemeId).isDark ? "dark" : "light";
  const setTheme = useCallback((next: AppTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(resolveThemeId(next), true);
    emitChange();
  }, []);
  useEffect(() => {
    applyTheme(resolvedThemeId);
  }, [resolvedThemeId]);
  return { theme, setTheme, resolvedTheme, resolvedThemeId } as const;
}
```

