### 7. NEW: `apps/web/src/components/ThemeSelector.tsx`

Replaces the inline radiogroup in the settings page. Accepts controlled props so the parent can own state (easier to test in isolation).

```tsx
import { BUILT_IN_THEMES, type BuiltInThemeId, type ThemeDefinition } from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";
import type { AppTheme } from "~/hooks/useTheme";

interface ThemeSelectorProps {
  value: AppTheme;
  resolvedThemeId: BuiltInThemeId;
  onChange: (next: AppTheme) => void;
}

export function ThemeSelector({ value, resolvedThemeId, onChange }: ThemeSelectorProps) {
  return (
    <div role="radiogroup" aria-label="Theme preference" className="space-y-2">
      {/* System option */}
      <button
        type="button"
        role="radio"
        aria-checked={value === "system"}
        onClick={() => onChange("system")}
        className={cn(
          "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
          value === "system"
            ? "border-primary/60 bg-primary/8 text-foreground"
            : "border-border bg-background text-muted-foreground hover:bg-accent",
        )}
      >
        <span className="flex flex-col">
          <span className="text-sm font-medium">System</span>
          <span className="text-xs">Match your OS appearance setting.</span>
        </span>
        {value === "system" && (
          <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Selected
          </span>
        )}
      </button>

      {/* Named themes */}
      {BUILT_IN_THEMES.map((def) => (
        <ThemeOption
          key={def.id}
          def={def}
          selected={value === def.id}
          onChange={onChange}
        />
      ))}
    </div>
  );
}

function ThemeOption({
  def,
  selected,
  onChange,
}: {
  def: ThemeDefinition;
  selected: boolean;
  onChange: (next: AppTheme) => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={() => onChange(def.id)}
      className={cn(
        "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
    >
      <span className="flex flex-col gap-1.5">
        <span className="text-sm font-medium">{def.name}</span>
        {/* Color swatches: background, accent, sidebar */}
        <span className="flex items-center gap-1" aria-hidden="true">
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.background }}
          />
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.accent }}
          />
          <span
            className="size-3 rounded-full border border-black/10"
            style={{ background: def.colors.sidebar }}
          />
        </span>
      </span>
      {selected && (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      )}
    </button>
  );
}
```

Note: swatches read from `def.colors` (JS values), not CSS variables — they render correctly before the browser resolves `data-theme` CSS.

