/**
 * T3 Code theme system — shared type definitions and built-in theme catalogue.
 *
 * Keeping this in the shared package means the web app and any future surfaces
 * (desktop shell, marketing site, etc.) always consume identical definitions.
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type BuiltInThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Semantic color tokens for every named area of the UI.
 * Values are plain CSS color strings (hex / oklch / etc.) so they can be
 * embedded in JS (e.g. swatch previews) as well as in CSS custom properties.
 */
export type ThemeColorTokens = {
  /** Main canvas / page background */
  background: string;
  /** Primary text color */
  foreground: string;
  /** Brand / interactive accent */
  accent: string;
  /** Sidebar / navigation surface */
  sidebar: string;
  /** Code-editor pane surface */
  editor: string;
  /** Integrated terminal surface */
  terminal: string;
  /** Bottom status bar surface */
  statusBar: string;
};

export type ThemeDefinition = {
  id: BuiltInThemeId;
  label: string;
  description: string;
  /** Drives the Tailwind `.dark` class — keep this in sync with the palette. */
  colorScheme: "light" | "dark";
  colors: ThemeColorTokens;
};

