      terminal: "#0a0a0c",
      statusBar: "#1c1c1f",
    },
  },

  "t3-midnight": {
    id: "t3-midnight",
    label: "T3 Midnight",
    description: "Ultra-dark indigo theme for late-night sessions.",
    colorScheme: "dark",
    colors: {
      background: "#0b0c14",
      foreground: "#e2e4f0",
      accent: "#5b7fff",
      sidebar: "#0d0f1a",
