import { useCallback, useEffect, useSyncExternalStore } from "react";

import { BUILT_IN_THEMES, BUILT_IN_THEME_IDS, type BuiltInThemeId } from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

export type SelectableTheme = BuiltInThemeId | "system";

// ---------------------------------------------------------------------------
// Module-level store (shared across all hook instances)
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";
const BUILT_IN_ID_SET = new Set<string>(BUILT_IN_THEME_IDS);

type ThemeSnapshot = {
  theme: SelectableTheme;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read the persisted theme, migrating legacy "dark"/"light" values on-the-fly.
 * The migration is read-time only — no writes to localStorage happen here.
 */
function getStored(): SelectableTheme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "system") return "system";
  if (raw !== null && BUILT_IN_ID_SET.has(raw)) return raw as BuiltInThemeId;
  return "system";
}

/**
 * Resolve a selectable theme (which may be "system") to a concrete built-in
 * theme ID using the OS preference when needed.
 */
function resolveThemeId(theme: SelectableTheme, systemDark: boolean): BuiltInThemeId {
  if (theme === "system") {
    return systemDark ? "t3-dark" : "t3-light";
  }
  return theme;
}

/**
 * Write the current theme into the DOM:
 *   • `data-theme="<id>"` — consumed by CSS `[data-theme]` blocks
 *   • `.dark` class       — consumed by Tailwind dark-variant rules
 *
 * Optionally suppresses CSS transitions for a flash-free switch.
 */
function applyTheme(theme: SelectableTheme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const systemDark = getSystemDark();
  const themeId = resolveThemeId(theme, systemDark);
  const def = BUILT_IN_THEMES[themeId];
  const isDark = def.colorScheme === "dark";

  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.setAttribute("data-theme", themeId);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
applyTheme(getStored());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot !== null &&
    lastSnapshot.theme === theme &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Re-apply + notify when the OS colour-scheme preference changes.
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Sync across browser tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { theme, systemDark } = snapshot;

  const themeId = resolveThemeId(theme, systemDark);

  /**
   * `resolvedTheme` remains `"light" | "dark"` for full backward-compatibility
   * with every component that already consumes it (DiffPanel, ChatMarkdown, …).
   */
  const resolvedTheme: "light" | "dark" = BUILT_IN_THEMES[themeId].colorScheme;

  const setTheme = useCallback((next: SelectableTheme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep the DOM in sync whenever the stored selection changes.
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme } as const;
}

