import type { ReactNode } from "react";

import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Mounts a permanent subscriber to the theme store so that OS colour-scheme
 * preference changes are always reflected in the DOM — even when no other
 * component using `useTheme` is currently rendered.
 *
 * Place this high in the tree (e.g. in the router `Wrap`) so it lives for the
 * full lifetime of the application.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Calling the hook here keeps exactly one subscriber alive at all times.
  // The hook itself handles media-query and storage-event listeners.
  useTheme();
  return <>{children}</>;
}

