      description: string;
      /** Hex colours used for live preview swatches (background, accent, sidebar). */
      swatches: [string, string, string];
    };

const THEME_OPTIONS: ThemeOption[] = [
  {
    value: "system",
    label: "System",
    description: "Match your OS appearance setting.",
  },
  ...BUILT_IN_THEME_IDS.map((id) => {
    const def = BUILT_IN_THEMES[id];
    return {
      value: def.id as SelectableTheme,
      label: def.label,
      description: def.description,
      swatches: [def.colors.background, def.colors.accent, def.colors.sidebar] as [
        string,
        string,
        string,
      ],
    };
  }),
];

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Radio-group style theme picker with colour swatches.
 *
 * Swatches use the JS colour values from `ThemeDefinition.colors` — not CSS
 * custom properties — so they render correctly before the browser has
 * processed the `data-theme` attribute on `<html>`.
 */
export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {THEME_OPTIONS.map((option) => {
        const selected = theme === option.value;
        return (
          <button
            key={option.value}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => {
              setTheme(option.value);
            }}
          >
            <span className="flex flex-col gap-0.5">
              <span className="text-sm font-medium">{option.label}</span>
              <span className="text-xs">{option.description}</span>
            </span>

            <div className="flex shrink-0 items-center gap-2">
              {option.swatches ? (
                <div className="flex gap-1" aria-hidden="true">
                  {option.swatches.map((color, i) => (
                    <span
                      key={i}
                      className="block h-4 w-4 rounded-sm ring-1 ring-black/10"
                      style={{ backgroundColor: color }}
                    />
                  ))}
                </div>
              ) : null}

              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

